import{_ as i,o as a,c as r,ag as l}from"./chunks/framework.NIzFHKo_.js";const u=JSON.parse('{"title":"Firefly","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/40_service_apps/120_applications/firefly.md","filePath":"10_core/40_service_apps/120_applications/firefly.md"}'),t={name:"10_core/40_service_apps/120_applications/firefly.md"};function o(n,e,s,c,p,d){return a(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="firefly" tabindex="-1">Firefly <a class="header-anchor" href="#firefly" aria-label="Permalink to &quot;Firefly&quot;">​</a></h1><p>Firefly is the planned finance-management application for the QiAccess personal system.</p><p>Its job is to make money activity visible, reviewable, and reportable without turning daily life into accounting overhead.</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Firefly should become the finance command layer for:</p><ul><li>account tracking</li><li>transaction review</li><li>category and context cleanup</li><li>household and caregiver spending visibility</li><li>exportable reporting</li></ul><h2 id="relationship-to-qiaccess" tabindex="-1">Relationship To QiAccess <a class="header-anchor" href="#relationship-to-qiaccess" aria-label="Permalink to &quot;Relationship To QiAccess&quot;">​</a></h2><p>QiAccess should remain the front door.</p><p>Firefly should be a dedicated linked app that opens from QiAccess when the task is:</p><ul><li>reviewing spending</li><li>tracking money movement</li><li>preparing finance reports</li><li>clarifying household, legal, business, or caregiver-related expenses</li></ul><h2 id="working-scope" tabindex="-1">Working Scope <a class="header-anchor" href="#working-scope" aria-label="Permalink to &quot;Working Scope&quot;">​</a></h2><p>Firefly is intended to cover:</p><ul><li>personal finance review</li><li>household expense tracking</li><li>caregiver-related costs</li><li>business and legal expense visibility where needed</li><li>reporting and export support</li></ul><p>It should not try to become a bloated general-purpose accounting suite in the first version.</p><h2 id="mvp-direction" tabindex="-1">MVP Direction <a class="header-anchor" href="#mvp-direction" aria-label="Permalink to &quot;MVP Direction&quot;">​</a></h2><p>The first version should focus on:</p><ol><li>accounts</li><li>transactions</li><li>import or manual entry</li><li>review inbox</li><li>categorization</li><li>reporting</li><li>exports</li></ol><h2 id="starting-workflows" tabindex="-1">Starting Workflows <a class="header-anchor" href="#starting-workflows" aria-label="Permalink to &quot;Starting Workflows&quot;">​</a></h2><h3 id="daily-use" tabindex="-1">Daily use <a class="header-anchor" href="#daily-use" aria-label="Permalink to &quot;Daily use&quot;">​</a></h3><ol><li>Open Firefly from QiAccess.</li><li>Review new or uncategorized transactions.</li><li>Assign category, context, or person where needed.</li><li>Check current balances, spending, or recent activity.</li><li>Export or report when needed.</li></ol><h3 id="key-reporting-uses" tabindex="-1">Key reporting uses <a class="header-anchor" href="#key-reporting-uses" aria-label="Permalink to &quot;Key reporting uses&quot;">​</a></h3><ul><li>household spending</li><li>caregiver support costs</li><li>business or legal-related expenses</li><li>uncategorized money that still needs cleanup</li></ul><h2 id="existing-reference" tabindex="-1">Existing Reference <a class="header-anchor" href="#existing-reference" aria-label="Permalink to &quot;Existing Reference&quot;">​</a></h2><p>The earlier <a href="./../40_productivity/qiledger">QiLedger Blueprint</a> already contains a much deeper finance architecture draft.</p><p>Treat that page as source material for Firefly rather than the final product name.</p><h2 id="initial-build-rule" tabindex="-1">Initial Build Rule <a class="header-anchor" href="#initial-build-rule" aria-label="Permalink to &quot;Initial Build Rule&quot;">​</a></h2><p>Build Firefly as a dedicated app with a narrow finance mission.</p><p>Do not overload QiAccess Start with ledger screens that belong inside the finance app itself.</p>',28)])])}const f=i(t,[["render",o]]);export{u as __pageData,f as default};
